# Deprecated aliases — lazy warning via __getattr__ (PEP 562)
_DEPRECATED_ALIASES = {
    "Status": "OrderStatus",
    "Kbars": "KBars",
    "UsageStatus": "UsageOut",
    "SettlementLegacy": "Settlement",
}

import importlib as _importlib
_SUBMODULES = (
    "constant", "order", "error", "position", "reserve", "data", "account",
    "contracts", "stream_data_type", "watchlist",
)

def __getattr__(name):
    if name in _DEPRECATED_ALIASES:
        import warnings
        warnings.warn(
            f"sj.{name} is deprecated, use sj.{_DEPRECATED_ALIASES[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return globals()[_DEPRECATED_ALIASES[name]]
    if name in _SUBMODULES:
        mod = _importlib.import_module(f".{name}", __name__)
        globals()[name] = mod
        return mod
    raise AttributeError(f"module 'shioaji' has no attribute {name!r}")


# ============================================================================
# api.quote proxy — deprecated, use api.subscribe/api.unsubscribe directly
# ============================================================================

class _QuoteProxy:
    """Deprecated proxy for api.quote -- use api.subscribe/api.unsubscribe directly."""

    def __init__(self, client):
        self._client = client

    def __getattr__(self, name):
        import warnings
        warnings.warn(
            f"api.quote.{name} is deprecated, use api.{name} directly",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(self._client, name)


@property
def _quote_proxy(self):
    return _QuoteProxy(self)


Shioaji.quote = _quote_proxy
ShioajiAsync.quote = _quote_proxy

# api.Order — backward compat (original shioaji sets self.Order = Order)
Shioaji.Order = Order
ShioajiAsync.Order = Order
